<template>
  <div class="q-pa-md">
         <p v-if="!editMode">{{ model }}</p>

        <q-select
          filled
          v-model="modelMultiple"
          :multiple="multiple"
          :options="options"
          :use-chips="multiple"
          stack-label
          label="Multiple selection"
        />
  </div>
</template>

<script>
import { ref } from 'vue'
import DataLoadMixin from '../components/DataLoadMixin'

export default {
    name: 'ForeignKey',
    mixins: [DataLoadMixin],
    props:{
        editMode:{
          type:Boolean,
          required:false,
          default:false
        },
        index:{
            type: Number,
            required: true
        },
        key:{
            type: String,
            default: ''
        },
        multiple:{
            type: Boolean,
            default: false
        },
        selected:{
            type: Array,
            default: []
        }
    },
    data () {
        return {
        modelMultiple: ref([]),

        options: []
        }
    },
    methods: {
        onInput (val) {
        console.log('onInput', val)
        },
        onFilter (val, update) {
            update(() => {
                const needle = val.toLowerCase()
                return this.options.filter(v => v.toLowerCase().indexOf(needle) > -1)
            })
        },
    },
    watch:{
        modelMultiple: function (val) {
          if(!this.multiple){
            val = val.value
          }else{
            val=val.map(item=>item.value)
          }
          if(this.key==''){
            this.$emit('childEvent', val, this.index)
          }else{
            this.$emit('childEvent', val, this.key)
          }
        }
      
    },
    async mounted(){
    if (this.model=='User'){
      console.log(this.service)
      await this.service.service.getUsers().then((data) => {
        console.log('Start')
        console.log(data.data)
        // var rows = Object.entries(data.data).map(([key, value]) => {
        //   return { label:value.name, value:key };
        // });
        var rows = data.data.map((value) => {
          return { label:value.displayName, value:value.uid };
        });
        this.options = ref(rows)
        console.log(this.options)
      })
    }else{
      console.log(this.service)
      await this.service.db.on('value', (snapshot) => {
            const data = snapshot.val();
            console.log(data)
            if(data==null || data==undefined){
              return
            }
            var rows = Object.entries(data).map(([key, value]) => {
              return { label:value.name, value:key };
            });
            this.options = ref(rows)
        });
      }
    }
}
</script>
